import React, { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';

const AnimusGlitch = () => {
  const location = useLocation();
  const [isGlitching, setIsGlitching] = useState(false);

  const [blocks, setBlocks] = useState([]);

  // Generate random scattered blocks when route changes
  useEffect(() => {
    const newBlocks = Array.from({ length: 45 }).map(() => {
      const top = Math.random() * 100; 
      const left = Math.random() * 100;
      const width = Math.random() * 200 + 20; // 20px to 220px wide
      const height = Math.random() * 6 + 2;   // 2px to 8px thick
      const delay = Math.random() * 0.15;     
      const duration = Math.random() * 0.2 + 0.1; 

      const colorRoll = Math.random();
      const background = colorRoll > 0.9 ? '#ff003c' : colorRoll > 0.8 ? '#00ffff' : '#ffffff';

      // Half scale left, half scale right, some scale center
      const dirRoll = Math.random();
      const origin = dirRoll > 0.66 ? 'left' : dirRoll > 0.33 ? 'right' : 'center';

      return { top, left, width, height, delay, duration, background, origin };
    });
    setBlocks(newBlocks);
  }, [location.pathname]);

  useEffect(() => {
    setIsGlitching(true);
    const timer = setTimeout(() => setIsGlitching(false), 450); 
    return () => clearTimeout(timer);
  }, [location.pathname]);

  if (!isGlitching) return null;

  return (
    <div className="animus-glitch-overlay">
      <div className="glitch-flash"></div>
      {blocks.map((b, i) => (
        <div 
          key={i} 
          className="glitch-block"
          style={{
            top: `${b.top}%`,
            left: `${b.left}%`,
            width: `${b.width}px`,
            height: `${b.height}px`,
            background: b.background,
            transformOrigin: b.origin,
            animationDelay: `${b.delay}s`,
            animationDuration: `${b.duration}s`
          }}
        ></div>
      ))}
    </div>
  );
};

export default AnimusGlitch;

import React from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { motion, LayoutGroup } from 'framer-motion';

const BottomNav = () => {
  const location = useLocation();

  const navItems = [
    { path: '/web', icon: '/web.png', label: 'Web' },
    { path: '/apps', icon: '/phone-person.png', label: 'Apps' },
    { path: '/', icon: '/assassins-creed-logo.png', label: 'Home', center: true },
    { path: '/projects', icon: '/project.png', label: 'Work' },
    { path: '/contact', icon: '/contact.png', label: 'Mail' },
  ];

  return (
    <nav className="nav-island-wrapper">
      <div className="nav-island-container">
        <LayoutGroup>
          {navItems.map((item) => {
            const isActive = location.pathname === item.path;

            return (
              <NavLink
                key={item.path}
                to={item.path}
                className={({ isActive }) => 
                  `nav-item ${item.center ? 'nav-center-fab' : ''} ${isActive ? 'active' : ''}`
                }
              >
                {isActive && !item.center && (
                  <motion.div 
                    layoutId="sliding-blob"
                    className="nav-active-blob"
                    transition={{ type: "spring", stiffness: 350, damping: 30 }}
                  />
                )}

                <motion.div 
                  className="nav-icon-wrapper"
                  animate={{ 
                    y: isActive ? (item.center ? -5 : -4) : 0,
                    scale: isActive ? 1.15 : 1
                  }}
                  transition={{ type: "spring", stiffness: 400, damping: 12 }}
                >
                  {typeof item.icon === 'string' ? (
                    <img 
                      src={item.icon} 
                      alt={item.label} 
                      className={`nav-icon-img ${item.center ? 'nav-center-icon' : ''}`} 
                    />
                  ) : (
                    item.icon
                  )}
                  {isActive && !item.center && (
                    <motion.div layoutId="nav-dot" className="nav-dot-indicator" />
                  )}
                </motion.div>

                {!item.center && (
                  <span className="nav-label">{item.label}</span>
                )}
              </NavLink>
            );
          })}
        </LayoutGroup>
      </div>
    </nav>
  );
};

export default BottomNav;

